{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01HEL39nYyEnbag7Hz26Gum8","type":"tool_result","content":"     1→/**
     2→ * Session Runner - Claude Code Subprocess Management
     3→ *
     4→ * Spawns Claude Code headless sessions with streaming JSON output,
     5→ * enforces tool restrictions, and manages session lifecycle.
     6→ */
     7→
     8→import { spawn, type ChildProcess } from 'node:child_process';
