    25→ * Always disallow the mw CLI to ensure agents use MCP tools (FR-002)
    26→ */
    27→const MANDATORY_DISALLOWED_TOOLS = ['Bash(mw)'];
    28→
    29→/**
    30→ * Parse a streaming JSON line from Claude Code output
    31→ */
    32→function parseStreamLine(line: string): StreamEvent | null {
    33→  if (!line.trim()) {
    34→    return null;
    35→  }
    36→
    37→  try {
    38→    const parsed = JSON.parse(line);
    39→    return {
    40→      type: parsed.type || 'message',
    41→      timestamp: new Date(),
    42→      content: parsed,
    43→    };
    44→  } catch {
    45→    // Malformed JSON - log and skip
    46→    console.warn('[session-runner] Malformed JSON line:', line.substring(0, 100));
    47→    return null;
    48→  }
    49→}
    50→
    51→/**
    52→ * Extract session_id from a stream event
    53→ * Session ID appears in result events
    54→ */
    55→function extractSessionId(event: StreamEvent): string | null {
    56→  const content = event.content as Record<string, unknown>;
    57→
    58→  // Check common locations for session_id
    59→  if (content.session_id && typeof content.session_id === 'string') {
    60→    return content.session_id;
    61→  }
    62→
    63→  // Check nested in result
    64→  if (content.result && typeof content.result === 'object') {
    65→    const result = content.result as Record<string, unknown>;
    66→    if (result.session_id && typeof result.session_id === 'string') {
    67→      return result.session_id;
    68→    }
    69→  }
    70→
    71→  return null;
    72→}
    73→
    74→/**
